def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for x in range(8, 2, -2):
                for y in range(1, x + 5):
                    term = ((ratio - x) ** 7) / (x * y + 1.5)
                    priority += term * np.sin(ratio * y / (x + 0.5)) * np.exp(-y/x)
            priority += (np.cosh(ratio - 7) * np.sin(ratio * 1.3)) ** 2
            for z in range(1, 6):
                priority += np.tanh(ratio / (z + 0.5)) * np.cos(z * ratio) * 1.7
        elif 5 < ratio <= 8:
            s = 0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    outer = ((ratio - p) ** 4) * np.sin(ratio * p * 1.1)
                    inner = np.log1p(q * 0.7)
                    s += np.tanh(outer / inner) * 1.5
            priority = s + np.log(ratio) * 8 - np.tanh(ratio - 5) * 3
            if bin_cap > item * 5:
                priority -= np.exp(-2 * ratio) * 6
            else:
                priority += np.sqrt(ratio) * 3.5
        elif 2.5 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2.5) ** r) / (r * 2.2) * np.cos((r + 1) * ratio * 1.2)
            priority = s * np.cos(9 * ratio) - np.log(ratio) * 5 + np.tanh(3 * (5 - ratio)) * 2
            for m in range(1, 8):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 2.5) ** m) / m
        elif 1 <= ratio < 2.5:
            s = 0
            for n in range(1, 14):
                s += ((2.5 - ratio) ** n) / (n ** 1.8 + 0.7) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 1.5:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for k in range(1, 6):
                priority += np.sin(k * ratio * i * 1.1) * ((ratio - 1) ** k) / k
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 20):
                s += ((1 - ratio) ** t) / (t * 3.5) * np.sin(t * ratio * 2.1)
            priority = s + 0.5 / (bin_cap + 4)
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.5:
            s = 0
            for u in range(1, 18):
                s += ((0.5 - ratio) ** u) / (u * 5) * np.cos(u * ratio * 2.4)
            priority = s + 1 / (bin_cap + 6)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.8) * 5
            for v in range(1, 10):
                priority += ((0.5 - ratio) ** v) / (v * 8) * np.sin(item * v * 1.3)
        else:
            s = 0
            for w in range(1, 14):
                s += ((0.15 - ratio) ** w) / (w * 6) * np.sin(w * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for z in range(1, 12):
                priority += ((0.15 - ratio) ** z) / (z * 9) * np.cos(item * z * 1.05)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
